// Login handler
app.post('/login', (req, res) => {
  const { username, password, rememberMe } = req.body;

  if (!username || !password) {
    return res.status(400).send('Username and password are required');
  }

  const user = usersDB[username.toLowerCase()];
  if (!user) {
    return res.status(401).send(`
      <html><body style="font-family:Arial;text-align:center;margin-top:50px;">
        <h2>Login Failed</h2><p>Invalid username or password.</p>
        <a href="/login">Try again</a>
      </body></html>
    `);
  }

  // Verify password using constant-time comparison
  const inputHash = hashPassword(password);
  const isValid = crypto.timingSafeEqual(
    Buffer.from(inputHash, 'hex'),
    Buffer.from(user.passwordHash, 'hex')
  );

  if (!isValid) {
    return res.status(401).send(`
      <html><body style="font-family:Arial;text-align:center;margin-top:50px;">
        <h2>Login Failed</h2><p>Invalid username or password.</p>
        <a href="/login">Try again</a>
      </body></html>
    `);
  }

  // Set session cookie
  res.cookie('session_user', user.username, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/'
  });

  // Handle Remember Me
  if (rememberMe === 'true') {
    const cookieValue = createRememberMeCookie(user.username);

    res.cookie(COOKIE_NAME, cookieValue, {
      maxAge: REMEMBER_ME_DAYS * 24 * 60 * 60 * 1000,
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      path: '/'
    });

    console.log(`Remember-me token created for user: ${user.username}`);
  }

  console.log(`User logged in: ${user.username} (Remember Me: ${rememberMe === 'true'})`);
  res.redirect('/dashboard');
});

