// Logout
app.get('/logout', (req, res) => {
  // Invalidate the remember-me token
  const rememberCookie = req.cookies ? req.cookies[COOKIE_NAME] : null;
  if (rememberCookie) {
    invalidateToken(rememberCookie);
  }

  // Clear all cookies
  res.clearCookie(COOKIE_NAME, { path: '/' });
  res.clearCookie('session_user', { path: '/' });

  console.log('User logged out, cookies cleared');
  res.redirect('/login');
});

// Home redirect
app.get('/', (req, res) => {
  if (req.user) {
    return res.redirect('/dashboard');
  }
  res.redirect('/login');
});

// --- API endpoint for legacy system compatibility ---
app.post('/api/verify-remember-me', (req, res) => {
  const cookieValue = req.body.token || (req.cookies ? req.cookies[COOKIE_NAME] : null);

  if (!cookieValue) {
    return res.json({ valid: false, message: 'No token provided' });
  }

  const username = validateRememberMeCookie(cookieValue);
  if (username) {
    return res.json({ valid: true, username: username });
  }

  return res.json({ valid: false, message: 'Invalid or expired token' });
});

